#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;



vec2 uv1 = (vUv-.5) * uAspect.xy;

vec2 uv6 = uv1;
float z = q31*length((abs(uv1.x)-abs(uv1.y)));
vec2 d = normalize(uv1);
vec2 rs = clamp(tan(z)*d,-2,2);
vUv += .1*lum(GetBlur1(vUv))*d;
vUv -= rs/(20+0*q27);

uv6 = .4*sin(vUv*14+rand_frame);
mus = .01/(length(uv6));
mus *= .3*(1+roam_cos);
//mus = .2;

vec3 crisp= texture(sampler_main,(vUv-.5)*(.95+.1*q28*z)+.5);

vec3 ret1 = crisp + mus;

q25 = 1;
ret = q25*(ret1*.99-.025) + (1-q25)* GetPixel(vUvOriginal);


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv2 = vUv;
if(uv2.x >= 0.5) {uv2.x = 1-uv2.x;}
if(uv2.y >= 0.5) {uv2.y = 1-uv2.y;}

//float1 cs = cos(0.25*3.14159);
//float1 sn = sin(0.25*3.14159);
//vec2 uv3 = uv2;
//uv2.x = uv3.x * cs - uv3.y * sn;
//uv2.y = uv3.x * sn + uv3.y * cs;

vUv.x=uv2.x;
vUv.y=uv2.y;


   d = uTexSize.zw*4;
   d_uv = vUv;
   dx = GetBlur1(d_uv + vec2(1,0)*d) - GetBlur1(d_uv - vec2(1,0)*d);
   dy = GetBlur1(d_uv + vec2(0,1)*d) - GetBlur1(d_uv - vec2(0,1)*d);
   d_uv += vec2(dx.x,dy.x)*.03;

ret = mix(GetBlur2(d_uv),GetPixel(d_uv),0.4);
//ret = (ret.y-ret.x*0.5)*mix(vec3(1.5,0.6,0),1,ret.x)*1.4; // original
ret = (ret.y-ret.x*0.86)*mix(vec3(1.5 + 10.1*q28 , 0.6 + .18*q27, 0 + 0*0.1*q1),1,ret.x)*1.4;

ret = mix(ret,0,GetBlur1(d_uv-vec2(1,1)*uTexSize.zw*32).z*0.6);
ret = mix(ret,2,GetPixel(vUv).z*0.36);

  fragColor = ret;
}
